var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddSingleton<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
builder.Services.AddHttpClient("api")
    .ConfigureHttpMessageHandlerBuilder(b =>
    {
        ((HttpClientHandler)b.PrimaryHandler).UseCookies = false;
    });
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

arguments.new_str:
using System.Net;

var builder = WebApplication.CreateBuilder(args);

// Breaking change fix: Scoped IUserService was captured by singleton ICacheService.
// .NET 9 enables ValidateScopes in development, which throws on this violation.
// Fix: Register ICacheService as scoped so both lifetimes align.
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// Breaking change fix: HttpClientFactory now uses SocketsHttpHandler by default.
// Casting PrimaryHandler to HttpClientHandler throws InvalidCastException.
// Fix: Use ConfigurePrimaryHttpMessageHandler with the desired handler type.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// Breaking change fix: Trace-level HttpClientFactory logs now redact all header
// values by default. Allowlist the specific non-sensitive headers you need to see.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        !h.Equals("X-Request-Id", StringComparison.OrdinalIgnoreCase)
        && !h.Equals("X-Correlation-Id", StringComparison.OrdinalIgnoreCase)));

// Breaking change fix: ForwardedHeadersMiddleware now ignores X-Forwarded-*
// headers from proxies not in KnownProxies / KnownNetworks.
// Add your reverse-proxy address so headers are processed.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

